effect llm {
    f complete(prompt: &s) -> s;
}

effect tools {
    f run_code(code: &s) -> R[s, s];
    f read_file(path: &s) -> R[s, s];
    f write_file(path: &s, content: &s) -> R[(), s];
}

S AgentResult {
    plan: [s]~,
    outputs: [s]~,
    errors: [s]~,
}

+f agent_loop(task: &s) -> AgentResult / llm, tools, io {
    v plan_prompt = f"Break this task into steps:\n{task}";
    v plan_text = llm.complete(&plan_prompt);
    v steps = plan_text.lines().to_vec();
    m outputs: [s]~ = [];
    m errors: [s]~ = [];
    @ step : &steps {
        v code_prompt = f"Write MAGE code for: {step}";
        v code = llm.complete(&code_prompt);
        ? tools.run_code(&code) {
            R.Ok(out) => outputs.push(out),
            R.Err(err) => errors.push(f"Step failed: {err}"),
        }
    }
    @AgentResult { plan: steps, outputs: outputs, errors: errors }
}

