struct AgentResult { plan: Vec<String>, outputs: Vec<String>, errors: Vec<String> }

trait LlmClient { fn complete(&self, prompt: &str) -> String; }
trait ToolRunner {
    fn run_code(&self, code: &str) -> Result<String, String>;
    fn read_file(&self, path: &str) -> Result<String, String>;
    fn write_file(&self, path: &str, content: &str) -> Result<(), String>;
}

pub fn agent_loop(task: &str, llm: &dyn LlmClient, tools: &dyn ToolRunner) -> AgentResult {
    let plan_prompt = format!("Break this task into steps:\n{}", task);
    let plan_text = llm.complete(&plan_prompt);
    let steps: Vec<String> = plan_text.lines().map(|s| s.to_string()).collect();
    let mut outputs = Vec::new();
    let mut errors = Vec::new();
    for step in &steps {
        let code_prompt = format!("Write Rust code for: {}", step);
        let code = llm.complete(&code_prompt);
        match tools.run_code(&code) {
            Ok(out) => outputs.push(out),
            Err(err) => errors.push(format!("Step failed: {}", err)),
        }
    }
    AgentResult { plan: steps, outputs, errors }
}

