E AgentRole { Planner, Coder, Reviewer, Tester }

S SubTask {
    id: u32,
    description: s,
    assigned_to: AgentRole,
    result: ?s,
}

S Pipeline {
    tasks: [SubTask]~,
}

I Pipeline {
    +f new() -> Pipeline { @Pipeline { tasks: [] } }
    +f plan(&!self, goal: &s) / llm {
        v plan = llm.complete(&f"Plan subtasks for: {goal}");
        v lines = plan.lines();
        m id: u32 = 0;
        @ line : lines {
            self.tasks.push(@SubTask {
                id: id, description: line.to_string(),
                assigned_to: AgentRole.Coder, result: ?None,
            });
            id = id + 1;
        }
    }
    +f execute(&!self) / llm, tools {
        m i: usize = 0;
        loop {
            ? i >= self.tasks.len() { break; }
            v prompt = f"As a {self.tasks[i].assigned_to}, do: {self.tasks[i].description}";
            v output = llm.complete(&prompt);
            self.tasks[i].result = ?Some(output);
            i = i + 1;
        }
    }
    +f report(&self) -> s {
        m lines: [s]~ = [];
        @ task : &self.tasks {
            v status = ? task.result { ?Some(_) => "done", ?None => "pending" };
            lines.push(f"[{task.id}] {status}: {task.description}");
        }
        lines.join("\n")
    }
}

rust_equivalent.rs_source:
enum AgentRole { Planner, Coder, Reviewer, Tester }
struct SubTask { id: u32, description: String, assigned_to: AgentRole, result: Option<String> }
struct Pipeline { tasks: Vec<SubTask> }

impl Pipeline {
    pub fn new() -> Self { Self { tasks: Vec::new() } }
    pub fn plan(&mut self, goal: &str, llm: &dyn LlmClient) {
        let plan = llm.complete(&format!("Plan subtasks for: {}", goal));
        for (id, line) in plan.lines().enumerate() {
            self.tasks.push(SubTask { id: id as u32, description: line.to_string(), assigned_to: AgentRole::Coder, result: None });
        }
    }
    pub fn execute(&mut self, llm: &dyn LlmClient) {
        for task in &mut self.tasks {
            let prompt = format!("As a {:?}, do: {}", task.assigned_to, task.description);
            task.result = Some(llm.complete(&prompt));
        }
    }
    pub fn report(&self) -> String {
        self.tasks.iter().map(|t| {
            let status = if t.result.is_some() { "done" } else { "pending" };
            format!("[{}] {}: {}", t.id, status, t.description)
        }).collect::<Vec<_>>().join("\n")
    }
}

