S CompileResult {
    success: bool,
    output: s,
    errors: [s]~,
}

+f self_correct(
    task: &s,
    max_retries: u32,
) -> R[s, s] / llm, tools {
    m code = llm.complete(&f"Write MAGE code: {task}");
    m attempt: u32 = 0;
    loop {
        v result = tools.compile(&code);
        ? result.success { ret R.Ok(code); }
        attempt = attempt + 1;
        ? attempt >= max_retries {
            ret R.Err(f"Failed after {max_retries} attempts");
        }
        v error_context = result.errors.join("\n");
        code = llm.complete(&f"Fix these errors in the code:\nErrors:\n{error_context}\nCode:\n{code}");
    }
}

rust_equivalent.rs_source:
struct CompileResult { success: bool, output: String, errors: Vec<String> }

pub fn self_correct(
    task: &str, max_retries: u32,
    llm: &dyn LlmClient, compiler: &dyn Compiler,
) -> Result<String, String> {
    let mut code = llm.complete(&format!("Write Rust code: {}", task));
    let mut attempt = 0;
    loop {
        let result = compiler.compile(&code);
        if result.success { return Ok(code); }
        attempt += 1;
        if attempt >= max_retries { return Err(format!("Failed after {} attempts", max_retries)); }
        let error_context = result.errors.join("\n");
        code = llm.complete(&format!("Fix these errors:\nErrors:\n{}\nCode:\n{}", error_context, code));
    }
}

