S ToolDef {
    name: s,
    description: s,
    handler: f(s) -> R[s, s],
}

S ToolRegistry { tools: {s: ToolDef} }

I ToolRegistry {
    +f new() -> ToolRegistry { @ToolRegistry { tools: {} } }
    +f register(&!self, tool: ToolDef) {
        self.tools.insert(tool.name.clone(), tool);
    }
    +f list(&self) -> [s]~ {
        self.tools.keys().to_vec()
    }
    +f invoke(&self, name: &s, args: s) -> R[s, s] {
        ? self.tools.get(name) {
            ?Some(tool) => (tool.handler)(args),
            ?None => R.Err(f"unknown tool: {name}"),
        }
    }
    +f describe(&self) -> s {
        m lines: [s]~ = [];
        @ (name, tool) : &self.tools {
            lines.push(f"{name}: {tool.description}");
        }
        lines.join("\n")
    }
}

