use std::collections::HashMap;

struct ToolDef { name: String, description: String, handler: fn(String) -> Result<String, String> }
struct ToolRegistry { tools: HashMap<String, ToolDef> }

impl ToolRegistry {
    pub fn new() -> Self { Self { tools: HashMap::new() } }
    pub fn register(&mut self, tool: ToolDef) { self.tools.insert(tool.name.clone(), tool); }
    pub fn list(&self) -> Vec<String> { self.tools.keys().cloned().collect() }
    pub fn invoke(&self, name: &str, args: String) -> Result<String, String> {
        match self.tools.get(name) {
            Some(tool) => (tool.handler)(args),
            None => Err(format!("unknown tool: {}", name)),
        }
    }
    pub fn describe(&self) -> String {
        self.tools.iter().map(|(name, tool)| format!("{}: {}", name, tool.description))
            .collect::<Vec<_>>().join("\n")
    }
}

