E Role { User, Assistant, System }

S Message {
    role: Role,
    content: s,
    timestamp: u64,
}

S Memory {
    messages: [Message]~,
    max_messages: usize,
}

I Memory {
    +f new(max: usize) -> Memory { @Memory { messages: [], max_messages: max } }
    +f add(&!self, role: Role, content: s, ts: u64) {
        self.messages.push(@Message { role: role, content: content, timestamp: ts });
        ? self.messages.len() > self.max_messages {
            self.messages.remove(0);
        }
    }
    +f context_window(&self, n: usize) -> [&Message]~ {
        v start = ? self.messages.len() > n { self.messages.len() - n } : { 0 };
        self.messages[start..].to_vec()
    }
    +f summarize(&self) -> s / llm {
        v transcript = self.messages.iter()
            .map(fn(msg) => f"{msg.role}: {msg.content}")
            .join("\n");
        llm.complete(&f"Summarize this conversation:\n{transcript}")
    }
    +f search(&self, keyword: &s) -> [&Message]~ {
        self.messages.iter()
            .filter(fn(msg) => msg.content.contains(keyword))
            .to_vec()
    }
}

rust_equivalent.rs_source:
enum Role { User, Assistant, System }
struct Message { role: Role, content: String, timestamp: u64 }
struct Memory { messages: Vec<Message>, max_messages: usize }

impl Memory {
    pub fn new(max: usize) -> Self { Self { messages: Vec::new(), max_messages: max } }
    pub fn add(&mut self, role: Role, content: String, ts: u64) {
        self.messages.push(Message { role, content, timestamp: ts });
        if self.messages.len() > self.max_messages { self.messages.remove(0); }
    }
    pub fn context_window(&self, n: usize) -> &[Message] {
        let start = self.messages.len().saturating_sub(n);
        &self.messages[start..]
    }
    pub fn summarize(&self, llm: &dyn LlmClient) -> String {
        let transcript: String = self.messages.iter()
            .map(|m| format!("{:?}: {}", m.role, m.content)).collect::<Vec<_>>().join("\n");
        llm.complete(&format!("Summarize this conversation:\n{}", transcript))
    }
    pub fn search(&self, keyword: &str) -> Vec<&Message> {
        self.messages.iter().filter(|m| m.content.contains(keyword)).collect()
    }
}

