S Template {
    raw: s,
}

I Template {
    +f new(raw: s) -> Template { @Template { raw: raw } }
    +f render(&self, vars: &{s: s}) -> s {
        m result = self.raw.clone();
        @ (key, val) : vars {
            result = result.replace(&f"{{{key}}}", val);
        }
        // Handle {{#if key}}...{{/if}} blocks
        m pos: usize = 0;
        loop {
            v start_tag = result[pos..].find("{{#if ");
            ? start_tag {
                ?None => break,
                ?Some(si) => {
                    v abs_start = pos + si;
                    v end_tag_start = result[abs_start..].find("}}").unwrap() + abs_start;
                    v var_name = result[abs_start + 6..end_tag_start];
                    v block_end = result[end_tag_start..].find("{{/if}}").unwrap() + end_tag_start;
                    v block_content = result[end_tag_start + 2..block_end];
                    v has_val = vars.contains_key(&var_name.to_string());
                    v replacement = ? has_val { block_content } : { "" };
                    result = f"{result[..abs_start]}{replacement}{result[block_end + 7..]}";
                    pos = abs_start;
                },
            }
        }
        result
    }
}

