use std::collections::HashMap;

struct Template { raw: String }

impl Template {
    pub fn new(raw: String) -> Self { Self { raw } }
    pub fn render(&self, vars: &HashMap<String, String>) -> String {
        let mut result = self.raw.clone();
        for (key, val) in vars {
            result = result.replace(&format!("{{{}}}", key), val);
        }
        // Process conditionals (simplified)
        loop {
            if let Some(si) = result.find("{{#if ") {
                let end_tag = result[si..].find("}}").unwrap() + si;
                let var_name = &result[si+6..end_tag];
                let block_end = result[end_tag..].find("{{/if}}").unwrap() + end_tag;
                let block_content = &result[end_tag+2..block_end];
                let replacement = if vars.contains_key(var_name) { block_content.to_string() } else { String::new() };
                result = format!("{}{}{}", &result[..si], replacement, &result[block_end+7..]);
            } else { break; }
        }
        result
    }
}

