E FieldType { Str, Int, Bool, List }

S FieldDef { name: s, field_type: FieldType, required: bool }

S Schema { fields: [FieldDef]~ }

S ParsedOutput { values: {s: s} }

+f parse_output(text: &s, schema: &Schema) -> R[ParsedOutput, s] {
    m values: {s: s} = {};
    @ field : &schema.fields {
        v pattern = f"{field.name}:";
        v idx = text.find(&pattern);
        ? idx {
            ?Some(i) => {
                v start = i + pattern.len();
                v rest = text[start..].trim();
                v end = rest.find('\n').unwrap_or(rest.len());
                values.insert(field.name.clone(), rest[..end].trim().to_string());
            },
            ?None => {
                ? field.required {
                    ret R.Err(f"missing required field: {field.name}");
                }
            },
        }
    }
    R.Ok(@ParsedOutput { values: values })
}

