use std::collections::HashMap;

enum FieldType { Str, Int, Bool, List }
struct FieldDef { name: String, field_type: FieldType, required: bool }
struct Schema { fields: Vec<FieldDef> }
struct ParsedOutput { values: HashMap<String, String> }

pub fn parse_output(text: &str, schema: &Schema) -> Result<ParsedOutput, String> {
    let mut values = HashMap::new();
    for field in &schema.fields {
        let pattern = format!("{}:", field.name);
        if let Some(i) = text.find(&pattern) {
            let start = i + pattern.len();
            let rest = text[start..].trim();
            let end = rest.find('\n').unwrap_or(rest.len());
            values.insert(field.name.clone(), rest[..end].trim().to_string());
        } else if field.required {
            return Err(format!("missing required field: {}", field.name));
        }
    }
    Ok(ParsedOutput { values })
}

