E Capability { FileRead, FileWrite, NetAccess, CodeExec, LlmCall }

S Sandbox {
    allowed: [Capability]~,
    denied_log: [s]~,
}

I Sandbox {
    +f new(caps: [Capability]~) -> Sandbox {
        @Sandbox { allowed: caps, denied_log: [] }
    }
    +f check(&!self, cap: Capability) -> bool {
        v allowed = self.allowed.iter().any(fn(c) => c == &cap);
        ? !allowed {
            self.denied_log.push(f"denied: {cap}");
        }
        allowed
    }
    +f guarded_read(&!self, path: &s) -> R[s, s] / fs {
        ? self.check(Capability.FileRead) {
            fs.read_bytes(path).map(fn(b) => s.from_utf8(b).unwrap())
        } : {
            R.Err("file read not permitted")
        }
    }
    +f guarded_net(&!self, url: &s) -> R[s, s] / net {
        ? self.check(Capability.NetAccess) {
            net.get(url)
        } : {
            R.Err("network access not permitted")
        }
    }
    +f audit_log(&self) -> &[s]~ { &self.denied_log }
}

