#[derive(PartialEq)]
enum Capability { FileRead, FileWrite, NetAccess, CodeExec, LlmCall }

struct Sandbox { allowed: Vec<Capability>, denied_log: Vec<String> }

impl Sandbox {
    pub fn new(caps: Vec<Capability>) -> Self { Self { allowed: caps, denied_log: Vec::new() } }
    pub fn check(&mut self, cap: Capability) -> bool {
        let allowed = self.allowed.contains(&cap);
        if !allowed { self.denied_log.push(format!("denied: {:?}", cap)); }
        allowed
    }
    pub fn guarded_read(&mut self, path: &str) -> Result<String, String> {
        if self.check(Capability::FileRead) {
            std::fs::read_to_string(path).map_err(|e| e.to_string())
        } else { Err("file read not permitted".into()) }
    }
    pub fn audit_log(&self) -> &[String] { &self.denied_log }
}

