S CodeMetrics {
    compiles: bool,
    tests_passed: u32,
    tests_total: u32,
    token_count: u32,
    reference_tokens: u32,
    effects_correct: bool,
}

S Score {
    correctness: f64,
    efficiency: f64,
    style: f64,
    total: f64,
}

+f evaluate(metrics: &CodeMetrics) -> Score {
    v correctness: f64 = ? metrics.compiles {
        ? metrics.tests_total > 0 {
            metrics.tests_passed as f64 / metrics.tests_total as f64
        } : { 1.0 }
    } : { 0.0 };
    v efficiency: f64 = ? metrics.token_count > 0 {
        v ratio = metrics.reference_tokens as f64 / metrics.token_count as f64;
        ? ratio > 1.0 { 1.0 } : { ratio }
    } : { 0.0 };
    v style: f64 = ? metrics.effects_correct { 1.0 } : { 0.5 };
    v total = correctness * 0.6 + efficiency * 0.3 + style * 0.1;
    @Score { correctness: correctness, efficiency: efficiency, style: style, total: total }
}

rust_equivalent.rs_source:
struct CodeMetrics { compiles: bool, tests_passed: u32, tests_total: u32, token_count: u32, reference_tokens: u32, effects_correct: bool }
struct Score { correctness: f64, efficiency: f64, style: f64, total: f64 }

pub fn evaluate(metrics: &CodeMetrics) -> Score {
    let correctness = if metrics.compiles {
        if metrics.tests_total > 0 { metrics.tests_passed as f64 / metrics.tests_total as f64 } else { 1.0 }
    } else { 0.0 };
    let efficiency = if metrics.token_count > 0 {
        let ratio = metrics.reference_tokens as f64 / metrics.token_count as f64;
        ratio.min(1.0)
    } else { 0.0 };
    let style = if metrics.effects_correct { 1.0 } else { 0.5 };
    let total = correctness * 0.6 + efficiency * 0.3 + style * 0.1;
    Score { correctness, efficiency, style, total }
}

