S Rule {
    id: s,
    category: s,
    pattern: s,
    description: s,
    fix_template: s,
}

S RuleMatch {
    rule_id: s,
    location: s,
    suggestion: s,
}

S SkbEngine {
    rules: [Rule]~,
}

I SkbEngine {
    +f new() -> SkbEngine { @SkbEngine { rules: [] } }
    +f load(&!self, rule: Rule) { self.rules.push(rule); }
    +f query(&self, code: &s, context: &s) -> [RuleMatch]~ {
        m matches: [RuleMatch]~ = [];
        @ rule : &self.rules {
            ? code.contains(&rule.pattern) {
                v suggestion = rule.fix_template
                    .replace("{pattern}", &rule.pattern)
                    .replace("{context}", context);
                matches.push(@RuleMatch {
                    rule_id: rule.id.clone(),
                    location: rule.pattern.clone(),
                    suggestion: suggestion,
                });
            }
        }
        matches
    }
    +f categories(&self) -> [s]~ {
        m cats: [s]~ = [];
        @ rule : &self.rules {
            ? !cats.contains(&rule.category) {
                cats.push(rule.category.clone());
            }
        }
        cats
    }
}

rust_equivalent.rs_source:
struct Rule { id: String, category: String, pattern: String, description: String, fix_template: String }
struct RuleMatch { rule_id: String, location: String, suggestion: String }
struct SkbEngine { rules: Vec<Rule> }

impl SkbEngine {
    pub fn new() -> Self { Self { rules: Vec::new() } }
    pub fn load(&mut self, rule: Rule) { self.rules.push(rule); }
    pub fn query(&self, code: &str, context: &str) -> Vec<RuleMatch> {
        self.rules.iter().filter_map(|rule| {
            if code.contains(&rule.pattern) {
                let suggestion = rule.fix_template.replace("{pattern}", &rule.pattern).replace("{context}", context);
                Some(RuleMatch { rule_id: rule.id.clone(), location: rule.pattern.clone(), suggestion })
            } else { None }
        }).collect()
    }
    pub fn categories(&self) -> Vec<String> {
        let mut cats = Vec::new();
        for rule in &self.rules {
            if !cats.contains(&rule.category) { cats.push(rule.category.clone()); }
        }
        cats
    }
}
